export function getAllKevinNutterSlugs(): string[] {
  return kevinNutterPages.map((p) => p.slug);
}

export function getKevinNutterPageData(slug: string): KevinNutterTopicPage | undefined {
  return kevinNutterPages.find((p) => p.slug === slug);
}

export function getKevinNutterPageMetadata(slug: string): { title: string; description: string } | undefined {
  const page = kevinNutterPages.find((p) => p.slug === slug);
  if (!page) return undefined;
  return { title: page.metaTitle, description: page.metaDescription };
}
